                        { "operator": "==", "thresholdValue": "confirmedCompromised", "representation": "redBright", "text": "{0}" },
                        { "operator": "==", "thresholdValue": "atRisk", "representation": "orange", "text": "{0}" },
                        { "operator": "==", "thresholdValue": "remediated", "representation": "green", "text": "{0}" },
                        { "operator": "==", "thresholdValue": "confirmedSafe", "representation": "green", "text": "{0}" },
                        { "operator": "Default", "representation": "gray", "text": "{0}" }
