            },
            "name": "id-risk-detections-grid"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "AADUserRiskEvents\n| where TimeGenerated {TimeRange}\n| extend Country = tostring(Location.countryOrRegion)\n| where isnotempty(Country)\n| summarize Detections = count(), Users = dcount(UserPrincipalName), HighRisk = countif(RiskLevel == \"high\"), Compromised = countif(RiskState == \"confirmedCompromised\"), LastSeen = max(TimeGenerated) by Country\n| sort by Detections desc",
              "size": 0,
              "title": "Risk Detections by Country",
