              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": {
                "formatters": [
                  { "columnMatch": "Detections", "formatter": 8, "formatOptions": { "palette": "red" } },
                  { "columnMatch": "HighRisk", "formatter": 8, "formatOptions": { "palette": "orange" } },
                  { "columnMatch": "LastSeen", "formatter": 6 }
                ],
                "rowLimit": 1000,
