            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "AADUserRiskEvents\n| where TimeGenerated {TimeRange}\n| where isnotempty(IpAddress)\n| extend Country = tostring(Location.countryOrRegion)\n| summarize Detections = count(), Users = dcount(UserPrincipalName), DetectionTypes = make_set(RiskEventType, 8), HighRisk = countif(RiskLevel == \"high\"), LastSeen = max(TimeGenerated) by IpAddress, Country\n| top 25 by Detections desc",
              "size": 0,
              "title": "Top Risk Source IPs",
