            "customWidth": "50",
            "name": "id-risk-source-ips"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "SigninLogs\n| where TimeGenerated {TimeRange}\n| where RiskLevelDuringSignIn in (\"low\",\"medium\",\"high\") or RiskState in (\"atRisk\",\"confirmedCompromised\")\n| extend City = tostring(LocationDetails.city), Country = tostring(LocationDetails.countryOrRegion)\n| extend Place = strcat(City, iff(isnotempty(Country), strcat(\", \", Country), \"\"))\n| project TimeGenerated, User = UserPrincipalName, IPAddress, Location = Place, App = AppDisplayName, RiskLevel = RiskLevelDuringSignIn, RiskState, Result = ResultType\n| order by TimeGenerated desc",
