                  {
                    "columnMatch": "RiskLevel",
                    "formatter": 18,
                    "formatOptions": {
                      "thresholdsOptions": "colors",
                      "thresholdsGrid": [
                        { "operator": "==", "thresholdValue": "high", "representation": "redBright", "text": "{0}" },
                        { "operator": "==", "thresholdValue": "medium", "representation": "orange", "text": "{0}" },
                        { "operator": "==", "thresholdValue": "low", "representation": "yellow", "text": "{0}" },
                        { "operator": "Default", "representation": "gray", "text": "{0}" }
                      ]
                    }
