    {
      "type": 12,
      "content": {
        "version": "NotebookGroup/1.0",
        "groupType": "editable",
        "title": "Network & Threat Intel",
        "items": [
          {
            "type": 1,
            "content": {
              "json": "Microsoft Defender Threat Intelligence and network telemetry in one view. The top rows quantify the live MDTI and open-source indicator feed flowing into Sentinel; the catalog charts profile that intelligence by type, provider, confidence, threat family, and freshness. The correlation grids then match those indicators against every IP, domain, URL, and file hash your tenant actually logged, while the Graph API, Syslog, and sign-in panels expose the on-network and programmatic activity an adversary would generate.",
              "style": "info"
            },
            "name": "net-info"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "union isfuzzy=true\n  (ThreatIntelIndicators | where TimeGenerated {TimeRange} | summarize Value = count() | extend Metric = \"TI Indicators\", Sort = 1),\n  (ThreatIntelIndicators | where TimeGenerated {TimeRange} | where IsActive == true | summarize Value = count() | extend Metric = \"Active Indicators\", Sort = 2),\n  (ThreatIntelIndicators | where TimeGenerated {TimeRange} | where ObservableKey has \"ipv4-addr\" | summarize Value = dcount(ObservableValue) | extend Metric = \"Malicious IPs Tracked\", Sort = 3),\n  (ThreatIntelIndicators | where TimeGenerated {TimeRange} | where ObservableKey has \"domain-name\" | summarize Value = dcount(ObservableValue) | extend Metric = \"Malicious Domains Tracked\", Sort = 4),\n  (ThreatIntelIndicators | where TimeGenerated {TimeRange} | where ObservableKey has \"url\" | summarize Value = dcount(ObservableValue) | extend Metric = \"Malicious URLs Tracked\", Sort = 5),\n  (ThreatIntelIndicators | where TimeGenerated {TimeRange} | where ObservableKey has \"file:hashes\" | summarize Value = dcount(ObservableValue) | extend Metric = \"Malicious File Hashes\", Sort = 6)\n| project Metric, Value, Sort\n| sort by Sort asc",
              "size": 3,
              "title": "Threat Intelligence Coverage",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "tiles",
              "tileSettings": {
                "titleContent": { "columnMatch": "Metric", "formatter": 1 },
                "leftContent": {
                  "columnMatch": "Value",
                  "formatter": 12,
                  "formatOptions": { "palette": "red" },
                  "numberFormat": { "unit": 17, "options": { "style": "decimal", "maximumFractionDigits": 0 } }
                },
                "showBorder": true
              }
            },
            "name": "net-kpis"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "union isfuzzy=true\n  (MicrosoftGraphActivityLogs | where TimeGenerated {TimeRange} | summarize Value = count() | extend Metric = \"Graph API Calls\", Sort = 1),\n  (MicrosoftGraphActivityLogs | where TimeGenerated {TimeRange} | where ResponseStatusCode >= 400 | summarize Value = count() | extend Metric = \"Graph API Errors\", Sort = 2),\n  (MicrosoftGraphActivityLogs | where TimeGenerated {TimeRange} | summarize Value = dcount(tostring(IPAddress)) | extend Metric = \"Graph Source IPs\", Sort = 3),\n  (AADNonInteractiveUserSignInLogs | where TimeGenerated {TimeRange} | summarize Value = count() | extend Metric = \"Non-Interactive Sign-ins\", Sort = 4),\n  (Syslog | where TimeGenerated {TimeRange} | summarize Value = count() | extend Metric = \"Network Syslog Events\", Sort = 5)\n| project Metric, Value, Sort\n| sort by Sort asc",
              "size": 3,
              "title": "Network & API Telemetry",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "tiles",
              "tileSettings": {
                "titleContent": { "columnMatch": "Metric", "formatter": 1 },
                "leftContent": {
                  "columnMatch": "Value",
                  "formatter": 12,
                  "formatOptions": { "palette": "blue" },
                  "numberFormat": { "unit": 17, "options": { "style": "decimal", "maximumFractionDigits": 0 } }
                },
                "showBorder": true
              }
            },
            "name": "net-net-kpis"
          },
          {
            "type": 1,
            "content": {
              "json": "### Threat Intelligence Catalog\nThe live MDTI and open-source indicator feed flowing into Sentinel, profiled by indicator type, provider, confidence, threat family, and freshness. This is the raw intelligence the correlation grids further down match your telemetry against.",
              "style": "info"
            },
            "name": "net-cat-header"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "ThreatIntelIndicators\n| where TimeGenerated {TimeRange}\n| extend IndicatorType = tostring(split(ObservableKey, \":\")[0])\n| where isnotempty(IndicatorType)\n| summarize Indicators = count() by IndicatorType\n| sort by Indicators desc",
              "size": 0,
              "title": "Indicators by Type",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "barchart"
            },
            "customWidth": "50",
            "name": "net-ti-types"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "ThreatIntelIndicators\n| where TimeGenerated {TimeRange}\n| where IsActive == true\n| summarize Indicators = count() by Provider = SourceSystem\n| top 12 by Indicators desc",
              "size": 0,
              "title": "Indicators by Provider / Feed",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "barchart"
            },
            "customWidth": "50",
            "name": "net-ti-provider"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "ThreatIntelIndicators\n| where TimeGenerated {TimeRange}\n| where IsActive == true\n| extend Band = case(Confidence >= 90, \"90-100 Very High\", Confidence >= 70, \"70-89 High\", Confidence >= 50, \"50-69 Medium\", Confidence >= 1, \"1-49 Low\", \"0 Unscored\")\n| summarize Indicators = count() by Band\n| order by Band asc",
              "size": 0,
              "title": "Indicators by Confidence",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "barchart"
            },
            "customWidth": "33",
            "name": "net-ti-confidence"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "ThreatIntelIndicators\n| where TimeGenerated {TimeRange}\n| summarize Indicators = count() by Status = iff(IsActive == true, \"Active\", \"Revoked\")",
              "size": 0,
              "title": "Active vs Revoked",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "piechart"
            },
            "customWidth": "33",
            "name": "net-ti-status"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "ThreatIntelIndicators\n| where TimeGenerated {TimeRange}\n| where IsActive == true and isnotempty(Tags)\n| mv-expand Tag = split(Tags, \",\") to typeof(string)\n| extend Tag = trim(\" \", tostring(Tag))\n| where Tag !startswith \"p:\" and Tag !startswith \"ic:\" and Tag !startswith \"vic:\" and Tag !startswith \"gid:\" and Tag !startswith \"cid:\" and Tag !startswith \"ultime\" and isnotempty(Tag)\n| summarize Indicators = count() by ThreatTag = Tag\n| top 15 by Indicators desc",
              "size": 0,
              "title": "Top Threat Family Tags",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "barchart"
            },
            "customWidth": "34",
            "name": "net-ti-family"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "ThreatIntelIndicators\n| where TimeGenerated {TimeRange}\n| where IsActive == true\n| summarize NewIndicators = count() by bin(TimeGenerated, {TimeRange:grain})\n| order by TimeGenerated asc",
              "size": 0,
              "title": "Indicator Freshness (Ingested Over Time)",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "areachart"
            },
            "name": "net-ti-fresh"
          },
          {
            "type": 1,
            "content": {
              "json": "### MDTI Correlation Against Tenant Telemetry\nThe grids below correlate live threat-intel IP indicators against every IP your tenant logged across Entra sign-ins, non-interactive sign-ins, Graph API, the Azure control plane, and Office 365. An empty result is the healthy outcome: it means no currently tracked malicious IP has touched your environment in the selected window. Any row that appears is a confirmed brush with known-bad infrastructure and should be triaged immediately.",
              "style": "info"
            },
            "name": "net-corr-header"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "let tiIps = ThreatIntelIndicators\n  | where TimeGenerated {TimeRange}\n  | where ObservableKey has \"ipv4-addr\"\n  | distinct ObservableValue;\nunion isfuzzy=true\n  (SigninLogs | where TimeGenerated {TimeRange} | project IP = IPAddress, Source = \"Entra Sign in\", Actor = UserPrincipalName, TimeGenerated),\n  (AADNonInteractiveUserSignInLogs | where TimeGenerated {TimeRange} | project IP = IPAddress, Source = \"Non Interactive Sign in\", Actor = UserPrincipalName, TimeGenerated),\n  (MicrosoftGraphActivityLogs | where TimeGenerated {TimeRange} | project IP = tostring(IPAddress), Source = \"Graph API\", Actor = tostring(UserId), TimeGenerated),\n  (AzureActivity | where TimeGenerated {TimeRange} | project IP = CallerIpAddress, Source = \"Azure Control Plane\", Actor = Caller, TimeGenerated),\n  (OfficeActivity | where TimeGenerated {TimeRange} | project IP = tostring(extract(@\"(\\d+\\.\\d+\\.\\d+\\.\\d+)\", 1, ClientIP)), Source = \"Office 365\", Actor = UserId, TimeGenerated)\n| where isnotempty(IP) and IP in (tiIps)\n| summarize Matches = count(), Sources = make_set(Source, 6), Actors = make_set(Actor, 10), DistinctActors = dcount(Actor), LastSeen = max(TimeGenerated) by IP\n| sort by Matches desc",
              "size": 0,
              "title": "MDTI Match Known Bad IPs Across All Tenant Logs",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": {
                "formatters": [
                  { "columnMatch": "Matches", "formatter": 8, "formatOptions": { "palette": "red" } },
                  { "columnMatch": "DistinctActors", "formatter": 8, "formatOptions": { "palette": "orange" } },
                  { "columnMatch": "LastSeen", "formatter": 6 }
                ],
                "rowLimit": 5000,
                "sortBy": [ { "itemKey": "Matches", "sortOrder": 2 } ]
              }
            },
            "customWidth": "60",
            "name": "net-ti-match"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "let tiIps = ThreatIntelIndicators\n  | where TimeGenerated {TimeRange}\n  | where ObservableKey has \"ipv4-addr\"\n  | distinct ObservableValue;\nunion isfuzzy=true\n  (SigninLogs | where TimeGenerated {TimeRange} | project IP = IPAddress, Source = \"Entra Sign in\"),\n  (AADNonInteractiveUserSignInLogs | where TimeGenerated {TimeRange} | project IP = IPAddress, Source = \"Non Interactive Sign in\"),\n  (MicrosoftGraphActivityLogs | where TimeGenerated {TimeRange} | project IP = tostring(IPAddress), Source = \"Graph API\"),\n  (AzureActivity | where TimeGenerated {TimeRange} | project IP = CallerIpAddress, Source = \"Azure Control Plane\"),\n  (OfficeActivity | where TimeGenerated {TimeRange} | project IP = tostring(extract(@\"(\\d+\\.\\d+\\.\\d+\\.\\d+)\", 1, ClientIP)), Source = \"Office 365\")\n| where isnotempty(IP) and IP in (tiIps)\n| summarize Matches = count(), DistinctBadIPs = dcount(IP) by Source\n| sort by Matches desc",
              "size": 0,
              "title": "MDTI Matches by Log Source",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "barchart",
              "chartSettings": { "createOtherGroup": 0 }
            },
            "customWidth": "40",
            "name": "net-ti-match-chart"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "let tiIps = ThreatIntelIndicators\n  | where TimeGenerated {TimeRange}\n  | where ObservableKey has \"ipv4-addr\"\n  | distinct ObservableValue;\nunion isfuzzy=true\n  (SigninLogs | where TimeGenerated {TimeRange} | project IP = IPAddress, Source = \"Entra Sign in\", TimeGenerated),\n  (AADNonInteractiveUserSignInLogs | where TimeGenerated {TimeRange} | project IP = IPAddress, Source = \"Non Interactive Sign in\", TimeGenerated),\n  (MicrosoftGraphActivityLogs | where TimeGenerated {TimeRange} | project IP = tostring(IPAddress), Source = \"Graph API\", TimeGenerated),\n  (AzureActivity | where TimeGenerated {TimeRange} | project IP = CallerIpAddress, Source = \"Azure Control Plane\", TimeGenerated),\n  (OfficeActivity | where TimeGenerated {TimeRange} | project IP = tostring(extract(@\"(\\d+\\.\\d+\\.\\d+\\.\\d+)\", 1, ClientIP)), Source = \"Office 365\", TimeGenerated)\n| where isnotempty(IP) and IP in (tiIps)\n| summarize Hits = count() by bin(TimeGenerated, {TimeRange:grain}), Source\n| order by TimeGenerated asc",
              "size": 0,
              "title": "MDTI Hits Over Time (Known Bad IPs Touching the Tenant)",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "barchart",
              "chartSettings": { "createOtherGroup": 0 }
            },
            "name": "net-ti-hits-trend"
          },
          {
            "type": 1,
            "content": {
              "json": "### Microsoft Graph API & Network Telemetry\nGraph API is the primary programmatic surface into your tenant. Volume and error trends, status-code mix, source IPs, calling applications, and user agents expose anomalous automation, token abuse, and reconnaissance. Linux Syslog volume by facility rounds out the on-network picture.",
              "style": "info"
            },
            "name": "net-graph-header"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "MicrosoftGraphActivityLogs\n| where TimeGenerated {TimeRange}\n| summarize Calls = count(), Errors = countif(ResponseStatusCode >= 400) by bin(TimeGenerated, {TimeRange:grain})\n| order by TimeGenerated asc",
              "size": 0,
              "title": "Graph API Call Volume & Errors Over Time",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "barchart",
              "chartSettings": { "createOtherGroup": 0 }
            },
            "customWidth": "60",
            "name": "net-graph-vol"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "MicrosoftGraphActivityLogs\n| where TimeGenerated {TimeRange}\n| summarize Calls = count() by StatusClass = strcat(substring(tostring(ResponseStatusCode), 0, 1), \"xx\")\n| order by StatusClass asc",
              "size": 0,
              "title": "Graph API Status Class Mix",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "piechart"
            },
            "customWidth": "40",
            "name": "net-graph-status"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "MicrosoftGraphActivityLogs\n| where TimeGenerated {TimeRange}\n| where ResponseStatusCode >= 400\n| summarize Errors = count() by ResponseStatusCode\n| sort by Errors desc",
              "size": 0,
              "title": "Graph API Errors by Status Code (4xx/5xx)",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "barchart"
            },
            "customWidth": "50",
            "name": "net-graph-errors"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "MicrosoftGraphActivityLogs\n| where TimeGenerated {TimeRange}\n| where isnotempty(UserAgent)\n| summarize Calls = count() by UserAgent\n| top 15 by Calls desc",
              "size": 0,
              "title": "Top Graph API User Agents",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "barchart"
            },
            "customWidth": "50",
            "name": "net-graph-ua"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "MicrosoftGraphActivityLogs\n| where TimeGenerated {TimeRange}\n| summarize Calls = count(), Errors = countif(ResponseStatusCode >= 400), Apps = dcount(AppId), LastSeen = max(TimeGenerated) by SourceIP = tostring(IPAddress)\n| top 25 by Calls desc",
              "size": 0,
              "title": "Top Graph API Source IPs",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": {
                "formatters": [
                  { "columnMatch": "Calls", "formatter": 8, "formatOptions": { "palette": "blue" } },
                  { "columnMatch": "Errors", "formatter": 8, "formatOptions": { "palette": "red" } },
                  { "columnMatch": "Apps", "formatter": 8, "formatOptions": { "palette": "orange" } },
                  { "columnMatch": "LastSeen", "formatter": 6 }
                ],
                "rowLimit": 1000,
                "filter": true,
                "sortBy": [ { "itemKey": "Calls", "sortOrder": 2 } ]
              }
            },
            "customWidth": "50",
            "name": "net-graph-ip"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "MicrosoftGraphActivityLogs\n| where TimeGenerated {TimeRange}\n| summarize Calls = count(), Errors = countif(ResponseStatusCode >= 400), SourceIPs = dcount(tostring(IPAddress)), LastSeen = max(TimeGenerated) by Application = tostring(AppId)\n| top 25 by Calls desc",
              "size": 0,
              "title": "Top Graph API Calling Applications",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": {
                "formatters": [
                  { "columnMatch": "Calls", "formatter": 8, "formatOptions": { "palette": "blue" } },
                  { "columnMatch": "Errors", "formatter": 8, "formatOptions": { "palette": "red" } },
                  { "columnMatch": "SourceIPs", "formatter": 8, "formatOptions": { "palette": "orange" } },
                  { "columnMatch": "LastSeen", "formatter": 6 }
                ],
                "rowLimit": 1000,
                "filter": true,
                "sortBy": [ { "itemKey": "Calls", "sortOrder": 2 } ]
              }
            },
            "customWidth": "50",
            "name": "net-graph-app"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "Syslog\n| where TimeGenerated {TimeRange}\n| summarize Events = count() by bin(TimeGenerated, {TimeRange:grain}), Facility\n| order by TimeGenerated asc",
              "size": 0,
              "title": "Linux Syslog Volume by Facility",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "barchart",
              "chartSettings": { "createOtherGroup": 0 }
            },
            "name": "net-syslog-fac"
          },
          {
            "type": 1,
            "content": {
              "json": "### Sign-in Network Footprint\nThe network reach of identities: non-interactive sign-in source IPs (token refreshes and service flows that attackers abuse for stealth) and the per-user spread of distinct IPs and countries that flags account sharing, proxy abuse, and impossible-travel.",
              "style": "info"
            },
            "name": "net-signin-header"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "AADNonInteractiveUserSignInLogs\n| where TimeGenerated {TimeRange}\n| summarize SignIns = count(), Users = dcount(UserPrincipalName), Failures = countif(ResultType != 0), Apps = dcount(AppDisplayName), LastSeen = max(TimeGenerated) by SourceIP = IPAddress\n| top 25 by SignIns desc",
              "size": 0,
              "title": "Top Non-Interactive Sign-in Source IPs",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": {
                "formatters": [
                  { "columnMatch": "SignIns", "formatter": 8, "formatOptions": { "palette": "blue" } },
                  { "columnMatch": "Failures", "formatter": 8, "formatOptions": { "palette": "red" } },
                  { "columnMatch": "Users", "formatter": 8, "formatOptions": { "palette": "orange" } },
                  { "columnMatch": "LastSeen", "formatter": 6 }
                ],
                "rowLimit": 1000,
                "filter": true,
                "sortBy": [ { "itemKey": "SignIns", "sortOrder": 2 } ]
              }
            },
            "customWidth": "50",
            "name": "net-ni-ip"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "SigninLogs\n| where TimeGenerated {TimeRange}\n| extend Country = tostring(LocationDetails.countryOrRegion)\n| summarize SignIns = count(), DistinctIPs = dcount(IPAddress), Countries = dcount(Country), Failures = countif(ResultType != 0), Apps = dcount(AppDisplayName), LastSeen = max(TimeGenerated) by User = UserPrincipalName\n| top 25 by DistinctIPs desc",
              "size": 0,
              "title": "Per-User IP & Country Spread",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": {
                "formatters": [
                  { "columnMatch": "DistinctIPs", "formatter": 8, "formatOptions": { "palette": "orange" } },
                  { "columnMatch": "Countries", "formatter": 8, "formatOptions": { "palette": "red" } },
                  { "columnMatch": "Failures", "formatter": 8, "formatOptions": { "palette": "red" } },
                  { "columnMatch": "SignIns", "formatter": 8, "formatOptions": { "palette": "blue" } },
                  { "columnMatch": "LastSeen", "formatter": 6 }
                ],
                "rowLimit": 1000,
                "filter": true,
                "sortBy": [ { "itemKey": "DistinctIPs", "sortOrder": 2 } ]
              }
            },
            "customWidth": "50",
            "name": "net-signin-footprint"
          },
          {
            "type": 1,
            "content": {
              "json": "### MDTI Indicator Matches in M365\nBeyond IPs, MDTI tracks malicious **domains, URLs, and file hashes**. The grids below correlate those indicators against your Microsoft 365 estate, weaponized URLs landing in mail and SharePoint/OneDrive/Teams, and known-bad file hashes arriving as email attachments. A hit here is a confirmed brush with adversary infrastructure or tooling.",
              "style": "upsell"
            },
            "name": "net-ti-md-header"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "let tiDomains = ThreatIntelIndicators\n  | where TimeGenerated {TimeRange}\n  | where ObservableKey has \"domain-name\"\n  | distinct Indicator = tolower(tostring(ObservableValue));\nlet tiUrls = ThreatIntelIndicators\n  | where TimeGenerated {TimeRange}\n  | where ObservableKey has \"url\"\n  | distinct Indicator = tolower(tostring(ObservableValue));\nunion isfuzzy=true\n  (EmailUrlInfo | where TimeGenerated {TimeRange} | extend Url = tolower(tostring(Url)), Domain = tolower(tostring(UrlDomain)) | project Url, Domain, Source = \"Email URL\", TimeGenerated),\n  (OfficeActivity | where TimeGenerated {TimeRange} | where isnotempty(ObjectId) | extend Url = tolower(tostring(ObjectId)) | extend Domain = tolower(extract(@\"https?://([^/:]+)\", 1, Url)) | project Url, Domain, Source = \"Office 365 (SP/OneDrive/Teams)\", TimeGenerated)\n| where (isnotempty(Domain) and Domain in (tiDomains)) or (isnotempty(Url) and Url in (tiUrls))\n| extend Indicator = iff(Domain in (tiDomains), Domain, Url), IndicatorType = iff(Domain in (tiDomains), \"Domain\", \"URL\")\n| summarize Hits = count(), Sources = make_set(Source, 4), Example = any(Url), LastSeen = max(TimeGenerated) by Indicator, IndicatorType\n| sort by Hits desc",
              "size": 0,
              "title": "MDTI Match - Malicious Domains & URLs in M365",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": {
                "formatters": [
                  { "columnMatch": "Hits", "formatter": 8, "formatOptions": { "palette": "red" } },
                  { "columnMatch": "IndicatorType", "formatter": 1 },
                  { "columnMatch": "LastSeen", "formatter": 6 }
                ],
                "rowLimit": 5000,
                "filter": true,
                "sortBy": [ { "itemKey": "Hits", "sortOrder": 2 } ]
              },
              "sortBy": [ { "itemKey": "Hits", "sortOrder": 2 } ]
            },
            "name": "net-ti-url-match"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "let tiFiles = ThreatIntelIndicators\n  | where TimeGenerated {TimeRange}\n  | where ObservableKey has \"file:hashes\"\n  | distinct Hash = tolower(tostring(ObservableValue));\nunion isfuzzy=true\n  (EmailAttachmentInfo | where TimeGenerated {TimeRange} | extend Hash = tolower(tostring(SHA256)) | project Hash, FileName, FileType, Source = \"Email Attachment\", Actor = SenderFromAddress, TimeGenerated),\n  (EmailAttachmentInfo | where TimeGenerated {TimeRange} | extend Hash = tolower(tostring(SHA1)) | project Hash, FileName, FileType, Source = \"Email Attachment\", Actor = SenderFromAddress, TimeGenerated)\n| where isnotempty(Hash) and Hash in (tiFiles)\n| summarize Hits = count(), Files = make_set(FileName, 8), FileTypes = make_set(FileType, 8), Senders = make_set(Actor, 8), LastSeen = max(TimeGenerated) by Hash\n| sort by Hits desc",
              "size": 0,
              "title": "MDTI Match - Malicious File Hashes Delivered to M365",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": {
                "formatters": [
                  { "columnMatch": "Hits", "formatter": 8, "formatOptions": { "palette": "red" } },
                  { "columnMatch": "Hash", "formatter": 1 },
                  { "columnMatch": "LastSeen", "formatter": 6 }
                ],
                "rowLimit": 5000,
                "filter": true,
                "sortBy": [ { "itemKey": "Hits", "sortOrder": 2 } ]
              },
              "sortBy": [ { "itemKey": "Hits", "sortOrder": 2 } ]
            },
            "name": "net-ti-file-match"
          }
        ]
      },
      "conditionalVisibility": { "parameterName": "selectedTab", "comparison": "isEqualTo", "value": "4" },
      "name": "group-network"
    },
    {
      "type": 12,
      "content": {
        "version": "NotebookGroup/1.0",
        "groupType": "editable",
        "title": "Cloud & SaaS Activity",
        "items": [
          {
            "type": 1,
            "content": {
              "json": "Threat activity across Microsoft 365, Azure control plane, and Entra ID. Risky mailbox operations and inbox rules are classic business email compromise (BEC) tradecraft; Azure control plane changes and Entra audit events catch privilege abuse and persistence.",
              "style": "info"
            },
            "name": "cloud-info"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "union isfuzzy=true\n  (OfficeActivity | where TimeGenerated {TimeRange} | where Operation in (\"New-InboxRule\",\"Set-InboxRule\",\"UpdateInboxRules\",\"Add-MailboxPermission\") | summarize Value = count() | extend Metric = \"Risky Mailbox/Rule Ops\", Sort = 1),\n  (AuditLogs | where TimeGenerated {TimeRange} | where OperationName has \"Consent to application\" | summarize Value = count() | extend Metric = \"App Consent Grants\", Sort = 2),\n  (AuditLogs | where TimeGenerated {TimeRange} | where OperationName has \"Add member to role\" | summarize Value = count() | extend Metric = \"Privileged Role Adds\", Sort = 3),\n  (AuditLogs | where TimeGenerated {TimeRange} | where OperationName has \"conditional access\" | summarize Value = count() | extend Metric = \"Conditional Access Changes\", Sort = 4),\n  (AzureActivity | where TimeGenerated {TimeRange} | where ActivityStatusValue in (\"Failed\",\"Failure\") | summarize Value = count() | extend Metric = \"Failed Azure Ops\", Sort = 5)\n| project Metric, Value, Sort\n| sort by Sort asc",
              "size": 3,
              "title": "Cloud Threat Signals",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "tiles",
              "tileSettings": {
                "titleContent": { "columnMatch": "Metric", "formatter": 1 },
                "leftContent": {
                  "columnMatch": "Value",
                  "formatter": 12,
                  "formatOptions": { "palette": "red" },
                  "numberFormat": { "unit": 17, "options": { "style": "decimal", "maximumFractionDigits": 0 } }
                },
                "showBorder": true
              }
            },
            "name": "cloud-kpis"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "union isfuzzy=true\n  (OfficeActivity | where TimeGenerated {TimeRange} | where Operation in (\"New-InboxRule\",\"Set-InboxRule\",\"UpdateInboxRules\",\"Add-MailboxPermission\") | extend Category = \"Mailbox/Rule Ops\"),\n  (AuditLogs | where TimeGenerated {TimeRange} | where OperationName has \"Consent to application\" | extend Category = \"App Consent\"),\n  (AuditLogs | where TimeGenerated {TimeRange} | where OperationName has \"Add member to role\" | extend Category = \"Privileged Role Add\")\n| summarize Count = count() by bin(TimeGenerated, {TimeRange:grain}), Category\n| order by TimeGenerated asc",
              "size": 0,
              "title": "Cloud Threat Signals Over Time",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "areachart"
            },
            "customWidth": "60",
            "name": "cloud-office-trend"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "AzureActivity\n| where TimeGenerated {TimeRange}\n| where ActivityStatusValue in (\"Failed\",\"Failure\")\n| extend Op = tostring(split(OperationNameValue, \"/\")[-2])\n| summarize Count = count() by OperationNameValue\n| top 15 by Count desc",
              "size": 0,
              "title": "Failed Azure Control Plane Operations",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "barchart"
            },
            "customWidth": "40",
            "name": "cloud-azure-status"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "OfficeActivity\n| where TimeGenerated {TimeRange}\n| where Operation in (\"New-InboxRule\",\"Set-InboxRule\",\"Add-MailboxPermission\",\"Set-Mailbox\",\"UpdateInboxRules\")\n| project TimeGenerated, UserId, Operation, ClientIP, OfficeWorkload\n| order by TimeGenerated desc",
              "size": 0,
              "title": "Risky Mailbox and Inbox Rule Operations (BEC Tradecraft)",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": {
                "formatters": [
                  { "columnMatch": "TimeGenerated", "formatter": 6 },
                  { "columnMatch": "Operation", "formatter": 1 }
                ],
                "rowLimit": 5000,
                "sortBy": [ { "itemKey": "TimeGenerated", "sortOrder": 2 } ]
              }
            },
            "customWidth": "50",
            "name": "cloud-mailbox-ops"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "AuditLogs\n| where TimeGenerated {TimeRange}\n| where OperationName has_any (\"Add member to role\",\"Add eligible member to role\",\"Consent to application\",\"Add app role assignment\",\"Update conditional access policy\",\"Add service principal\",\"Reset password\",\"Certificates and secrets management\",\"Disable Strong Authentication\")\n| summarize Count = count(), LastSeen = max(TimeGenerated) by OperationName, Result\n| top 25 by Count desc",
              "size": 0,
              "title": "Sensitive Entra ID Operations (Privilege Abuse & Persistence)",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": {
                "formatters": [
                  { "columnMatch": "Count", "formatter": 8, "formatOptions": { "palette": "red" } },
                  { "columnMatch": "LastSeen", "formatter": 6 }
                ],
                "rowLimit": 1000,
                "sortBy": [ { "itemKey": "Count", "sortOrder": 2 } ]
              }
            },
            "customWidth": "50",
            "name": "cloud-audit-ops"
          },
          {
            "type": 1,
            "content": {
              "json": "### Email Security (Microsoft Defender for Office 365)\nMail-borne threats across the full MDO telemetry set: EmailEvents (verdicts and delivery), EmailUrlInfo (weaponized URLs), EmailAttachmentInfo (malicious files and hashes), EmailPostDeliveryEvents (ZAP remediation), and UrlClickEvents (Safe Links clicks). The tiles, trends and grids below surface what was blocked versus delivered, the senders and domains behind it, the URLs and attachments embedded in mail, and post-delivery clean-up, classic initial-access and credential-harvesting tradecraft the SOC must triage fast.\n\n> Note: this workbook reads the Log Analytics / Sentinel workspace. The richest threat verdicts (ThreatTypes, DetectionMethods) populate fully when opened in the unified Microsoft Defender portal; here the panels are built to also light up from delivery action, quarantine location, bulk-complaint level, and the always-populated URL, attachment, ZAP and click tables.",
              "style": "upsell"
            },
            "name": "cloud-email-header"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "union isfuzzy=true\n  (EmailEvents | where TimeGenerated {TimeRange} | where ThreatTypes has \"Malware\" | summarize Value = count() | extend Metric = \"Malware\", Sort = 1),\n  (EmailEvents | where TimeGenerated {TimeRange} | where ThreatTypes has \"Phish\" | summarize Value = count() | extend Metric = \"Phishing\", Sort = 2),\n  (EmailEvents | where TimeGenerated {TimeRange} | where ThreatTypes has \"Spam\" or BulkComplaintLevel >= 7 | summarize Value = count() | extend Metric = \"Spam / Bulk\", Sort = 3),\n  (EmailEvents | where TimeGenerated {TimeRange} | where DeliveryAction in (\"Blocked\",\"Replaced\") or DeliveryLocation in (\"Quarantine\",\"Failed\",\"Dropped\") | summarize Value = count() | extend Metric = \"Blocked / Quarantined\", Sort = 4),\n  (EmailEvents | where TimeGenerated {TimeRange} | where isnotempty(ThreatTypes) and DeliveryAction == \"Delivered\" | summarize Value = count() | extend Metric = \"Threats Delivered\", Sort = 5),\n  (EmailPostDeliveryEvents | where TimeGenerated {TimeRange} | summarize Value = count() | extend Metric = \"Post-Delivery (ZAP)\", Sort = 6)\n| project Metric, Value, Sort\n| sort by Sort asc",
              "size": 3,
              "title": "Email Threat Signals",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "tiles",
              "tileSettings": {
                "titleContent": { "columnMatch": "Metric", "formatter": 1 },
                "leftContent": {
                  "columnMatch": "Value",
                  "formatter": 12,
                  "formatOptions": { "palette": "red" },
                  "numberFormat": { "unit": 17, "options": { "style": "decimal", "maximumFractionDigits": 0 } }
                },
                "showBorder": true
              }
            },
            "name": "cloud-email-kpis"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "union isfuzzy=true\n  (EmailEvents | where TimeGenerated {TimeRange} | summarize Value = count() | extend Metric = \"Total Emails\", Sort = 1),\n  (EmailEvents | where TimeGenerated {TimeRange} | where EmailDirection == \"Inbound\" | summarize Value = count() | extend Metric = \"Inbound\", Sort = 2),\n  (EmailEvents | where TimeGenerated {TimeRange} | summarize Value = dcount(SenderFromDomain) | extend Metric = \"Sender Domains\", Sort = 3),\n  (EmailEvents | where TimeGenerated {TimeRange} | where UrlCount > 0 | summarize Value = count() | extend Metric = \"Emails w/ URLs\", Sort = 4),\n  (EmailEvents | where TimeGenerated {TimeRange} | where AttachmentCount > 0 | summarize Value = count() | extend Metric = \"Emails w/ Attachments\", Sort = 5),\n  (UrlClickEvents | where TimeGenerated {TimeRange} | summarize Value = count() | extend Metric = \"Safe Links Clicks\", Sort = 6)\n| project Metric, Value, Sort\n| sort by Sort asc",
              "size": 3,
              "title": "Mail Flow & Exposure",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "tiles",
              "tileSettings": {
                "titleContent": { "columnMatch": "Metric", "formatter": 1 },
                "leftContent": {
                  "columnMatch": "Value",
                  "formatter": 12,
                  "formatOptions": { "palette": "blue" },
                  "numberFormat": { "unit": 17, "options": { "style": "decimal", "maximumFractionDigits": 0 } }
                },
                "showBorder": true
              }
            },
            "name": "cloud-email-flow"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "EmailEvents\n| where TimeGenerated {TimeRange}\n| where isnotempty(ThreatTypes) or DeliveryAction in (\"Blocked\",\"Junked\",\"Replaced\") or DeliveryLocation in (\"Quarantine\",\"Junk\",\"Failed\",\"Dropped\") or BulkComplaintLevel >= 7\n| extend Verdict = case(ThreatTypes has \"Malware\", \"Malware\", ThreatTypes has \"Phish\", \"Phish\", ThreatTypes has \"Spam\", \"Spam\", DeliveryLocation == \"Quarantine\" or DeliveryAction == \"Blocked\", \"Blocked/Quarantined\", DeliveryAction == \"Junked\" or DeliveryLocation == \"Junk\", \"Junked\", BulkComplaintLevel >= 7, \"Bulk\", \"Other\")\n| summarize Count = count() by bin(TimeGenerated, {TimeRange:grain}), Verdict\n| order by TimeGenerated asc",
              "size": 0,
              "title": "Email Threats Over Time (by Verdict)",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "barchart",
              "chartSettings": { "createOtherGroup": 0 }
            },
            "customWidth": "60",
            "name": "cloud-email-trend"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "EmailEvents\n| where TimeGenerated {TimeRange}\n| where isnotempty(ThreatTypes) or DeliveryAction in (\"Blocked\",\"Junked\",\"Replaced\") or DeliveryLocation in (\"Quarantine\",\"Junk\",\"Failed\",\"Dropped\") or BulkComplaintLevel >= 7\n| extend Verdict = case(ThreatTypes has \"Malware\", \"Malware\", ThreatTypes has \"Phish\", \"Phish\", ThreatTypes has \"Spam\", \"Spam\", DeliveryLocation == \"Quarantine\" or DeliveryAction == \"Blocked\", \"Blocked/Quarantined\", DeliveryAction == \"Junked\" or DeliveryLocation == \"Junk\", \"Junked\", BulkComplaintLevel >= 7, \"Bulk\", \"Other\")\n| summarize Count = count() by Verdict\n| sort by Count desc",
              "size": 0,
              "title": "Threat Verdict Mix",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "piechart"
            },
            "customWidth": "40",
            "name": "cloud-email-verdict"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "EmailEvents\n| where TimeGenerated {TimeRange}\n| where isnotempty(ThreatTypes) or DeliveryAction in (\"Blocked\",\"Junked\",\"Replaced\") or DeliveryLocation in (\"Quarantine\",\"Junk\",\"Failed\",\"Dropped\") or BulkComplaintLevel >= 7\n| where isnotempty(SenderFromDomain)\n| summarize Threats = count() by SenderFromDomain\n| top 15 by Threats desc",
              "size": 0,
              "title": "Top Threat Sender Domains",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "barchart",
              "chartSettings": { "createOtherGroup": 0 }
            },
            "customWidth": "50",
            "name": "cloud-email-sender"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "EmailUrlInfo\n| where TimeGenerated {TimeRange}\n| where isnotempty(UrlDomain)\n| summarize Occurrences = count(), Emails = dcount(NetworkMessageId) by UrlDomain\n| top 15 by Occurrences desc",
              "size": 0,
              "title": "Top URL Domains in Mail",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "visualization": "barchart",
              "chartSettings": { "createOtherGroup": 0 }
            },
            "customWidth": "50",
            "name": "cloud-email-urldom"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "EmailEvents\n| where TimeGenerated {TimeRange}\n| where isnotempty(ThreatTypes) or DeliveryAction in (\"Blocked\",\"Junked\",\"Replaced\") or DeliveryLocation in (\"Quarantine\",\"Junk\",\"Failed\",\"Dropped\") or BulkComplaintLevel >= 7\n| extend Verdict = case(ThreatTypes has \"Malware\", \"Malware\", ThreatTypes has \"Phish\", \"Phish\", ThreatTypes has \"Spam\", \"Spam\", DeliveryLocation == \"Quarantine\" or DeliveryAction == \"Blocked\", \"Blocked/Quarantined\", DeliveryAction == \"Junked\" or DeliveryLocation == \"Junk\", \"Junked\", BulkComplaintLevel >= 7, \"Bulk\", \"Other\")\n| project TimeGenerated, Verdict, SenderFromAddress, SenderFromDomain, RecipientEmailAddress, Subject, ThreatNames, DetectionMethods, DeliveryAction, DeliveryLocation, EmailActionPolicy, BulkComplaintLevel, SenderIPv4, NetworkMessageId\n| order by TimeGenerated desc",
              "size": 0,
              "title": "Filtered & Malicious Emails - Full Detail",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
              "gridSettings": {
                "formatters": [
                  { "columnMatch": "TimeGenerated", "formatter": 6 },
                  {
                    "columnMatch": "Verdict",
                    "formatter": 18,
                    "formatOptions": {
                      "thresholdsOptions": "colors",
                      "thresholdsGrid": [
                        { "operator": "==", "thresholdValue": "Malware", "representation": "redBright", "text": "{0}" },
                        { "operator": "==", "thresholdValue": "Phish", "representation": "redBright", "text": "{0}" },
                        { "operator": "==", "thresholdValue": "Spam", "representation": "orange", "text": "{0}" },
                        { "operator": "==", "thresholdValue": "Bulk", "representation": "yellow", "text": "{0}" },
                        { "operator": "==", "thresholdValue": "Junked", "representation": "orange", "text": "{0}" },
                        { "operator": "==", "thresholdValue": "Blocked/Quarantined", "representation": "green", "text": "{0}" },
                        { "operator": "Default", "representation": "gray", "text": "{0}" }
                      ]
                    }
                  },
                  {
                    "columnMatch": "DeliveryAction",
                    "formatter": 18,
                    "formatOptions": {
                      "thresholdsOptions": "colors",
                      "thresholdsGrid": [
                        { "operator": "==", "thresholdValue": "Delivered", "representation": "redBright", "text": "{0}" },
                        { "operator": "==", "thresholdValue": "Junked", "representation": "orange", "text": "{0}" },
                        { "operator": "==", "thresholdValue": "Blocked", "representation": "green", "text": "{0}" },
                        { "operator": "==", "thresholdValue": "Replaced", "representation": "green", "text": "{0}" },
                        { "operator": "Default", "representation": "gray", "text": "{0}" }
                      ]
                    }
                  },
                  { "columnMatch": "BulkComplaintLevel", "formatter": 8, "formatOptions": { "palette": "orange", "min": 0, "max": 9 } }
                ],
                "rowLimit": 5000,
                "filter": true,
                "sortBy": [ { "itemKey": "TimeGenerated", "sortOrder": 2 } ]
              }
            },
            "name": "cloud-email-detail-grid"
          },
          {
            "type": 3,
            "content": {
              "version": "KqlItem/1.0",
              "query": "EmailUrlInfo\n| where TimeGenerated {TimeRange}\n| join kind=inner (EmailEvents | where TimeGenerated {TimeRange} | where isnotempty(ThreatTypes) or DeliveryAction in (\"Blocked\",\"Junked\",\"Replaced\") or DeliveryLocation in (\"Quarantine\",\"Junk\",\"Failed\",\"Dropped\") or BulkComplaintLevel >= 7 | project NetworkMessageId, MailThreat = ThreatTypes, SenderFromAddress, DeliveryAction) on NetworkMessageId\n| summarize Hits = count(), Emails = dcount(NetworkMessageId), Senders = dcount(SenderFromAddress), Verdicts = make_set(MailThreat, 8), LastSeen = max(TimeGenerated) by Url, UrlDomain\n| top 100 by Hits desc",
              "size": 0,
              "title": "Malicious URLs in Mail",
              "queryType": 0,
              "resourceType": "microsoft.operationalinsights/workspaces",
