              "query": "SigninLogs\n| where TimeGenerated {TimeRange}\n| extend Country = tostring(LocationDetails.countryOrRegion), City = tostring(LocationDetails.city)\n| where isnotempty(Country)\n| summarize SignIns = count(), Failures = countif(ResultType != 0), Users = dcount(UserPrincipalName), IPs = dcount(IPAddress), RiskySignIns = countif(RiskLevelDuringSignIn in (\"low\",\"medium\",\"high\")), HighRisk = countif(RiskLevelDuringSignIn == \"high\"), CABlocks = countif(ConditionalAccessStatus == \"failure\"), LegacyAuth = countif(ClientAppUsed in (\"Other clients\",\"IMAP4\",\"POP3\",\"SMTP\",\"MAPI\",\"Authenticated SMTP\",\"Exchange ActiveSync\",\"Exchange Web Services\",\"Exchange Online PowerShell\",\"Autodiscover\")) by Country, City\n| extend FailRate = round(100.0 * Failures / SignIns, 1)\n| project Country, City, SignIns, Failures, Users, IPs, RiskySignIns, HighRisk, CABlocks, LegacyAuth, FailRate\n| order by Failures desc, SignIns desc",
